def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n < 4) return 0

  val incr = Array.fill(n)(1L)
  for (i <- 1 until n) {
    if (nums(i) > nums(i - 1)) incr(i) = incr(i - 1) + 1
    else incr(i) = 1
  }

  val decr = Array.fill(n)(1L)
  for (i <- n - 2 downTo 0) {
    if (nums(i) > nums(i + 1)) decr(i) = decr(i + 1) + 1
    else decr(i) = 1
  }

  val incr2 = Array.fill(n)(1L)
  for (i <- n - 2 downTo 0) {
    if (nums(i) < nums(i + 1)) incr2(i) = incr2(i + 1) + 1
    else incr2(i) = 1
  }

  val prefix = Array.fill(n + 1)(0L)
  for (i <- 0 until n) {
    prefix(i + 1) = prefix(i) + nums(i)
  }

  var maxSum = Long.MinValue
  for (p <- 0 until n) {
    if (incr(p) >= 2 && decr(p) >= 2) {
      val q = p + decr(p) - 1
